const now = new Date();

return items.filter(item => {
  const status = (item.json.Status || '').trim();
  const nextAction = item.json.NextActionDate || '';

  if (status === 'Closed' || status === 'Replied') return false;
  if (!status) return true;
  if (nextAction && new Date(nextAction) <= now) return true;

  return false;
}).map(item => ({
  json: {
    ...item.json,
    Person: item.json['First Name'] || '',
    Company: item.json['Company Name'] || '',
    Role: item.json['Title'] || '',
    LinkedInURL: item.json['LinkedIn URL'] || '',
    Country: item.json['Country'] || '',
    CurrentStep: parseInt(item.json['Step']) || 0
  }
}));

